  ('locality-c5fb3965-moex-00018', 'locality-c5fb3965', 'locality-c5fb3965-moex-114-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '有關公務人員權利義務之敘述，下列何者錯誤？', '["甲為公立學校校長，有公務員服務法之適用", "乙為縣長之機要秘書，亦受公務人員任用法之保障，縣長對其機要職務不可隨時將其免職", "丙公務人員在職死亡者，其遺族丁可向丙之服務機關申辦撫卹", "戊為現職軍人，不得參加公務人員協會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "303", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
