  ('locality-c5fb3965-moex-00021', 'locality-c5fb3965', 'locality-c5fb3965-moex-114-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '甲向乙戶政事務所申請改名遭拒，下列敘述何者錯誤？', '["乙拒絕甲改名之行為性質為行政處分", "甲不服乙拒絕更名得依法循序提訴願、行政訴訟", "甲提起爭訟中，乙同意甲改名並為登記，且通知財稅機關改名之事實，該通知性質為行政處分", "財稅機關依乙通知，將甲所有稅籍姓名變更並通知甲，該通知甲稅籍變更之行為，為行政處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "303", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00022', 'locality-c5fb3965', 'locality-c5fb3965-moex-114-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '依行政程序法規定，關於行政處分之補正，下列敘述何者正確？', '["經聽證之行政處分，僅得於向行政法院起訴前補正", "必須記明之附款，得因事後記明而補正", "處分機關告知之救濟期間有錯誤時，應由該機關以通知補正之，並自通知送達之翌日起算法定 期間", "應以證書方式作成而未給予證書，得因事後補發而補正"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "303", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00023', 'locality-c5fb3965', 'locality-c5fb3965-moex-114-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '衛生福利部中央健康保險署與保險醫事服務機構可以簽訂全民健保契約，中央健康保險署得就醫 事服務機構申請同意為特約醫事服務機構之資格、程序、審查基準訂定法規命令，依實務見解， 關於該法規命令之敘述，下列何者正確？', '["授權是否具體明確，僅以該授權法律之文義為準", "法規命令之規範內容，衛生福利部享有判斷餘地", "屬於相對法律保留範圍", "衛生福利部得選擇訂定行政規則替代該法規命令"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "303", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00024', 'locality-c5fb3965', 'locality-c5fb3965-moex-114-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '下列何者非屬行政契約？', '["國家賠償協議", "臺北市與基隆市簽訂的區域間都市垃圾緊急處理互助協議書", "新北市社會住宅之租約", "衛生福利部與公費醫學生所簽訂重點科別培育公費醫學生契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "303", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00025', 'locality-c5fb3965', 'locality-c5fb3965-moex-114-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '外交部對A國為旅遊警示，意即「避免非必要旅行」。關於此旅遊警示之敘述，下列何者正確？', '["該旅遊警示欠缺直接法律效力，屬行政事實行為", "該旅遊警示由外交部單方發布，屬於行政處分", "該旅遊警示係對於不特定人民所為，屬於法規命令", "該旅遊警示僅有行政內部效力，屬於行政規則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "303", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00026', 'locality-c5fb3965', 'locality-c5fb3965-moex-114-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '不得因不知法規而免除行政處罰責任。但按其情節，得減輕或免除其處罰。所稱「不知法規」， 係指下列何者？', '["依行為人之社會地位及個人能力，對於該行為之合法性產生懷疑", "指行為人不知法規之可責性高低而言", "指違反行政法上義務行為人必須要對自己行為究係違反何法規之規定有所認知", "指行為人不知法規所「禁止」或「要求應為」之行為或不行為義務為何"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:58+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "303", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL)
